// 按照公式，我们需要 D[l] += a1。
// 但是！当前枚举到的就是 l (即 i)。
// 对于当前的 i，sumd1 和 sumd2 已经计算过了！
// 如果把 a1 加到 D[i] 里，当前的 sumd1 和 sumd2 享受不到这个增量，会导致后续状态错误。
// 所以，我们直接“手动”把本来该由 D[l] 产生的影响，打入到当前的 sumd1 和 sumd2 中！
sumd1 += a1;
sumd2 += a1;

void solve(int CASE)
{
	ll n, k; cin >> n >> k;
	var a = vector<ll>(n + 10);
	fb(i, n, 1)cin >> a[i];
	var D = vector<ll>(n + 10);
	ll ans = 0;
	ll sumd1 = 0, sumd2 = 0; // 动态维护两个 sum

	fa(i, 1, n - k + 1) {
		sumd1 += D[i];
		sumd2 += sumd1;
		a[i] -= sumd2;
		if (a[i] > 0) {
			ll cnt = (a[i] + k - 1) / k;
			ans += cnt;

			ll a1 = k * cnt; 
			ll d = -cnt;
			ll an = cnt;
			ll l = i, r = i + k - 1;

			a[i] -= a1;
			sumd1 += a1;
			sumd2 += a1;

			D[l] += a1;
			D[l + 1] += d - a1;
			D[r + 1] += -d - an;
			D[r + 2] += an;
		}
	}

	ll mxcnt = 0;
	fa(i, n - k + 2, n) {
		sumd1 += D[i];
		sumd2 += sumd1;
		a[i] -= sumd2;
		if (a[i] > 0) {
			ll jian = n - i + 1;
			ll cnt = (a[i] + jian - 1) / jian;
			mxcnt = max(mxcnt, cnt);
		}
	}
	ans += mxcnt;

	cout << ans << endl;
	return;
}
